<template>
   <div>
      <!-- 面包屑 -->
      <el-breadcrumb separator-class="el-icon-arrow-right">
         <el-breadcrumb-item :to="{ path: '/' }">首页</el-breadcrumb-item>
         <el-breadcrumb-item>用户管理</el-breadcrumb-item>
         <el-breadcrumb-item>用户列表</el-breadcrumb-item>
      </el-breadcrumb>
      <!-- 卡片 -->
      <el-card class="box-card">
         <!-- 扇框布局 -->
         <el-row :gutter="12">
            <el-col :span="8">
               <div class="grid-content bg-purple">
                  <!--     搜索input                            clearable小叉叉-->
                  <el-input placeholder="请输入内容" @clear="ajax" clearable v-model="user.query" class="input-with-select">
                     <el-button slot="append" @click="ajax()" icon="el-icon-search"></el-button>
                  </el-input>
               </div>
            </el-col>
            <!-- 添加按钮 -->
            <el-col :span="4">
               <div class="grid-content bg-purple">
                  <el-button type="primary" @click="dialogVisible = true">点击添加</el-button>
               </div>
            </el-col>
            <!-- 表格 -->
            <el-table :data="tableData" stripe style="width: 100%">
               <el-table-column type="index" label="#" width="40">
               </el-table-column>
               <el-table-column prop="username" label="姓名" width="180">
               </el-table-column>
               <el-table-column prop="email" label="邮箱" width="180">
               </el-table-column>
               <el-table-column prop="mobile" label="电话" width="180">
               </el-table-column>
               <el-table-column prop="role_name" label="角色" width="180">
               </el-table-column>
               <!-- 状态 -->
               <el-table-column prop="mg_state" label="状态" width="180">
                  <!-- 具名插槽   -->
                  <template slot-scope="scope">
                     <el-switch v-model="scope.row.mg_state" @change="change(scope.row.id,scope.row.mg_state)"
                        active-color="#409EFF" inactive-color="#DCDFE6">
                     </el-switch>
                  </template>
               </el-table-column>

               <el-table-column prop="" label="操作" width="180">
                  <!-- 具名插槽   -->
                  <template slot-scope="scope">
                     <!-- {{scope.row}} -->
                     <el-tooltip :enterable='false' content="编辑" placement="top">
                        <el-button type="primary" icon="el-icon-edit" @click="edit(scope.row)" circle></el-button>
                     </el-tooltip>

                     <el-tooltip :enterable='false' content="删除" placement="top">
                        <el-button type="danger" @click="del(scope.row.id)" icon="el-icon-delete" circle></el-button>
                     </el-tooltip>
                     <el-tooltip :enterable='false' content="权限管理" placement="top">
                        <el-button type="warning" icon="el-icon-star-off" circle></el-button>

                     </el-tooltip>

                  </template>
               </el-table-column>
            </el-table>
         </el-row>

      </el-card>
      <!-- 分页 -->
      <el-pagination @size-change="handleSizeChange" @current-change="handleCurrentChange" :page-sizes="[1, 2, 3, 4]"
         :page-size="4" layout="total, sizes, prev, pager, next, jumper" :total="total">
      </el-pagination>

      <!-- 弹出框  添加用户 -->
      <el-dialog title="添加用户" :visible.sync="dialogVisible" width="30%">
         <el-form :model="ruleForm" :rules="rules" ref="ruleForm" label-width="100px" class="demo-ruleForm">
            <el-form-item label="用户名" prop="username">
               <el-input v-model="ruleForm.username"></el-input>
            </el-form-item>
            <el-form-item label="密码" prop="password">
               <el-input v-model="ruleForm.password"></el-input>
            </el-form-item>
            <el-form-item label="邮箱" prop="email">
               <el-input v-model="ruleForm.email"></el-input>
            </el-form-item>
            <el-form-item label="电话" prop="mobile">
               <el-input v-model="ruleForm.mobile"></el-input>
            </el-form-item>
         </el-form>

         <span slot="footer" class="dialog-footer">
            <el-button @click="dialogVisible = false">取 消</el-button>
            <el-button type="primary" @click="add">确 定</el-button>
         </span>

      </el-dialog>


      <!-- 弹出框  修改用户 -->

      <el-dialog
      title="编辑用户"
      :visible.sync="edi"
      width="30%"
      >
      <el-form   label-width="180px">
         <el-form-item label="用户名">
            <el-input disabled v-model="b"></el-input>
         </el-form-item>
         <el-form-item label="邮箱">
            <el-input v-model="c"></el-input>
         </el-form-item>
         <el-form-item label="电话">
            <el-input v-model="d"></el-input>
         </el-form-item>
      </el-form>
      <span slot="footer" class="dialog-footer">
        <el-button @click="edi = false">取 消</el-button>
        <el-button type="primary" @click="quex()">确 定</el-button>
      </span>
    </el-dialog>





   </div>
</template>

<script>
   export default {
      data() {
         // 验证邮箱
         var checkAge = (rule, value, callback) => {
            let em = /^[a-z0-9]+([._\\-]*[a-z0-9])*@([a-z0-9]+[-a-z0-9]*[a-z0-9]+.){1,63}[a-z0-9]+$/
            if (em.test(value)) {
               callback();
            } else {
               callback(new Error('请输入正确的邮箱'));
            }
         };
         // 验证手机号
         var checkphone = (rule, value, callback) => {
            let em = /1[3|4|5|7|8][0-9]{9}$/
            if (em.test(value)) {
               callback();
            } else {
               callback(new Error('请输入正确的手机号'));
            }
         };
         return {
            tableData: [],
            from1:{
               username:'',
               email:'',
               mobile:''
            },
            a:'',
            b:'',
            c:'',
            d:'',
            user: {
               query: '',
               pagenum: 1,
               pagesize: 4,
            },
            total: 0,
            dialogVisible: false,
            edi: false,
            ruleForm: {
               username: "",
               password: '',
               email: '',
               mobile: ''
            },
            rules: {
               username: [
                  { required: true, message: '请输入用户名称', trigger: 'blur' },
                  // { min: 3, max: 12, message: '长度在 3 到 12 个字符', trigger: 'blur' }
               ],
               password: [
                  { required: true, message: '请输入密码', trigger: 'blur' },
                  // { min: 3, max: 12, message: '长度在 3 到 12 个字符', trigger: 'blur' }
               ],
               email: [
                  { required: true, message: '请输入邮箱', trigger: 'blur' },
                  // { min: 3, max: 12, message: '长度在 3 到 12 个字符', trigger: 'blur' }
                  { validator: checkAge, trigger: 'blur' }
               ],
               mobile: [
                  { required: true, message: '请输入电话', trigger: 'blur' },
                  // { min: 3, max: 12, message: '长度在 3 到 12 个字符', trigger: 'blur' }
                  { validator: checkphone, trigger: 'blur' }

               ],
            },
         };

      },
      created() {

      },
      mounted() {
         this.ajax()
      },
      methods: {
         ajax() {
            this.$http.get(`/users?query=${this.user.query}&pagenum=${this.user.pagenum}&pagesize=${this.user.pagesize}`).then((data) => {
               // console.log(data)
               this.tableData = data.data.data.users
               this.total = data.data.data.total
            })

         },
         handleSizeChange(val) {
            // console.log(`每页 ${val} 条`);
            this.user.pagesize = val
            this.ajax()
         },
         handleCurrentChange(val) {
            // console.log(`当前页: ${val}`);
            this.user.pagenum = val
            this.ajax()
         },
         // 删除方法
         del(i) {
            // console.log(i)
            this.$confirm('此操作将永久删除该用户, 是否继续?', '提示', {
               confirmButtonText: '确定',
               cancelButtonText: '取消',
               type: 'warning'
            }).then(() => {
               this.$message({
                  type: 'success',
                  message: '删除成功!'
               });
               this.$http.delete('/users/' + i).then(res => {
                  if (res.data.meta.msg == '删除成功') {
                     this.ajax()
                  }
               })
            })
         },
         // 创建用户
         add() {
            //   console.log(this.rules.name)
            this.$http.post('/users', this.ruleForm).then((res) => {
               console.log(res)
               if (res.data.meta.msg == '创建成功') {
                  this.$message({
                     message: res.data.meta.msg,
                     type: 'success',
                     duration: 1000
                  })
                  this.dialogVisible = false
                  this.ajax()
               }
            })

         },
         // 状态修改
         change(id, bool) {
            console.log(id, bool)
            this.$http.put(`/users/${id}/state/${bool}`).then(res => {
               console.log(res)
               if (res.data.meta.msg == "设置状态成功") {
                  this.$message({
                     message: res.data.meta.msg,
                     type: 'success',
                     duration: 1000
                  })
               }
            })
         },
         // 点击修改出来弹框
         edit(i) {
            console.log(i)
            this.a=i.id
            this.b=i.username
            this.c=i.email
            this.d=i.mobile
            console.log(this.c)
            this.edi=true


         },
         // 点击确定修改就修改
         quex(){
         //   console.log(this.a)
             this.$http.put(`/users/${this.a}`,{
               "email":this.c,
               "mobile":this.d
            }).then(res=>{
            console.log(res)
            if(res.data.meta.msg="更新成功"){
               this.ajax()
               this.$message({
                     message: res.data.meta.msg,
                     type: 'success',
                     duration: 1000
                  })
            }
            this.edi=false

            })

         }



      }
   };
</script>

<style scoped>
   .box-card {
      margin-top: 10px;
   }
</style>